require 'spikard'
require 'json'
require 'faraday'

RSpec.describe 'streaming' do
  let(:base_url) { ENV.fetch('TEST_SERVER_URL', 'http://localhost:8080') }
  let(:client) do
    Faraday.new(url: base_url) do |f|
      f.request :json
      f.response :json, content_type: /\bjson$/
    end
  end

  describe 'GET /stream/logfile' do
    it 'Streams binary log segments with control bytes' do
      response = client.get('/stream/logfile')
      expect(response.status).to eq(200)
      expect(response.body).to eq('LOG:\\u0000\\u0001\\u0002\\u0003|TAIL|\\u0007\\n')
      expect(response.headers['content-type']).to eq('application/octet-stream')
    end
  end

  describe 'GET /stream/csv-report' do
    it 'Streams CSV header and rows as discrete chunks' do
      response = client.get('/stream/csv-report')
      expect(response.status).to eq(200)
      expect(response.body).to eq('id,name,value\\n1,Alice,42\\n2,Bob,7\\n')
      expect(response.headers['content-type']).to eq('text/csv')
    end
  end

  describe 'GET /stream/json-lines' do
    it 'Streams newline-delimited JSON payload in small chunks' do
      response = client.get('/stream/json-lines')
      expect(response.status).to eq(200)
      expect(response.body).to eq('{"index":0,"payload":"alpha"}\\n{"index":1,"payload":"beta"}\\n{"index":2,"payload":"gamma"}\\n')
      expect(response.headers['content-type']).to eq('application/x-ndjson')
    end
  end
end
